#include <bits/stdc++.h>
using namespace std;
#define int long long
int ans=0;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,k;
	cin>>n>>k;
	vector<int>a(n+1),b(n+1);
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	for(int i=1; i<=n; i++) {
		cin>>b[i];
	}
	vector<int>l(n+5),r(n+5);
	l[0]=LLONG_MAX/2;
	r[n+1]=LLONG_MAX/2;
	for(int i=1; i<=n; i++) {
		l[i]=min(l[i-1],-k*i+b[i]);
	}
	for(int i=n; i>=1; i--) {
		r[i]=min(r[i+1],k*i+b[i]);
	}
	vector<int>dp(n+1);
	for(int i=1; i<=n; i++) {
		dp[i]=min(k*i+l[i],-k*i+r[i]);
	}

	for(int i=1; i<=n; i++) {
		ans+=dp[a[i]];
	}
	cout<<ans;
	return 0;
}
